namespace sv_76af6605520e4ea0b094446b07c04010.Services;

public class WarehouseStateService
{
    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — Central"),
        ("WH-004", "Warehouse D — South"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId == value) return;
            _currentWarehouseId = value;
            NotifyStateChanged();
        }
    }

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId).Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    private void NotifyStateChanged() => OnChange?.Invoke();
}

namespace sv_76af6605520e4ea0b094446b07c04010.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call with a random result (0–15).
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

@using sv_76af6605520e4ea0b094446b07c04010.Services
@inject WarehouseStateService WarehouseState

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap mb-0 small fw-semibold">Warehouse:</label>
    <select class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged"
            style="min-width: 200px;">
        @foreach (var wh in WarehouseStateService.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.CurrentWarehouseId = e.Value?.ToString() ?? "";
    }
}

@using sv_76af6605520e4ea0b094446b07c04010.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="position-relative">
    🔔
    @if (_lowStockCount > 0)
    {
        <span class="badge rounded-pill bg-danger position-absolute top-0 start-100 translate-middle"
              style="font-size: 0.65rem;">
            @_lowStockCount
        </span>
    }
</span>

@code {
    private int _lowStockCount;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        _cts = new CancellationTokenSource();
        _ = PollAlertsAsync(_cts.Token);
        await RefreshCountAsync();
    }

    private async void OnWarehouseChanged()
    {
        await RefreshCountAsync();
        await InvokeAsync(StateHasChanged);
    }

    /// <summary>
    /// Exposed so the Dashboard page can push fresh counts to us
    /// without duplicating the polling timer.
    /// </summary>
    [Parameter] public int? ExternalCount { get; set; }

    protected override void OnParametersSet()
    {
        if (ExternalCount.HasValue)
        {
            _lowStockCount = ExternalCount.Value;
        }
    }

    private async Task PollAlertsAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await RefreshCountAsync();
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshCountAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_76af6605520e4ea0b094446b07c04010.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h2>Warehouse Dashboard</h2>
<p class="text-muted">
    Managing: <strong>@WarehouseState.CurrentWarehouseName</strong>
    <span class="text-secondary small">(@WarehouseState.CurrentWarehouseId)</span>
</p>

<div class="row g-4 mt-2">
    <div class="col-md-4">
        <div class="card @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 fw-bold @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                    @_lowStockCount
                </p>
                <p class="card-text text-muted small">
                    Items below minimum level &bull; refreshes every 10 s
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Active Warehouse</h5>
                <p class="display-6 fw-semibold">@WarehouseState.CurrentWarehouseName</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Last Refreshed</h5>
                <p class="display-6 fw-semibold">@_lastRefreshed.ToString("T")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _lowStockCount;
    private DateTime _lastRefreshed = DateTime.Now;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await RefreshAsync();
        _cts = new CancellationTokenSource();
        _ = PollAsync(_cts.Token);
    }

    private async void OnWarehouseChanged()
    {
        await RefreshAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task PollAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastRefreshed = DateTime.Now;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

