@page "/dashboard"
@rendermode InteractiveServer
@using sv_76af6605520e4ea0b094446b07c04010.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h2>Warehouse Dashboard</h2>
<p class="text-muted">
    Managing: <strong>@WarehouseState.CurrentWarehouseName</strong>
    <span class="text-secondary small">(@WarehouseState.CurrentWarehouseId)</span>
</p>

<div class="row g-4 mt-2">
    <div class="col-md-4">
        <div class="card @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 fw-bold @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                    @_lowStockCount
                </p>
                <p class="card-text text-muted small">
                    Items below minimum level &bull; refreshes every 10 s
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Active Warehouse</h5>
                <p class="display-6 fw-semibold">@WarehouseState.CurrentWarehouseName</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Last Refreshed</h5>
                <p class="display-6 fw-semibold">@_lastRefreshed.ToString("T")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _lowStockCount;
    private DateTime _lastRefreshed = DateTime.Now;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await RefreshAsync();
        _cts = new CancellationTokenSource();
        _ = PollAsync(_cts.Token);
    }

    private async void OnWarehouseChanged()
    {
        await RefreshAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task PollAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastRefreshed = DateTime.Now;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

